@file:Suppress("ktlint:standard:max-line-length", "MaxLineLength")

package app.tvlink.ui.icons

import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.SolidColor
import androidx.compose.ui.graphics.vector.ImageVector
import androidx.compose.ui.graphics.vector.addPathNodes
import androidx.compose.ui.unit.dp

/**
 * 本地内嵌的 Material Symbols(Rounded)图标,viewport 960。
 *
 * 官方已停维护 material-icons/material-icons-extended 制品(旧样式、显著拖慢构建),
 * 推荐从 Google 字体图标取 XML 本地内嵌。本文件路径数据取自
 * github.com/google/material-design-icons 仓库
 * symbols/android/<name>/materialsymbolsrounded/<name>_24px.xml。
 *
 * 新增图标：同上路径取 XML,抄 pathData,加一个缓存 getter 即可。
 */
object AppIcons {
    private fun materialIcon(
        name: String,
        pathData: String,
        autoMirror: Boolean = false,
    ): ImageVector =
        ImageVector
            .Builder(
                name = name,
                defaultWidth = 24.dp,
                defaultHeight = 24.dp,
                viewportWidth = 960f,
                viewportHeight = 960f,
                autoMirror = autoMirror,
            ).addPath(pathData = addPathNodes(pathData), fill = SolidColor(Color.Black))
            .build()

